    -- This statement will cause a divide-by-zero error
    SELECT 10 / 0 AS Result;
END TRY
BEGIN CATCH
    PRINT 'An error occurred.';
    PRINT ERROR_MESSAGE(); -- Displays the error message
END CATCH;

